// menu.js - تصميم جميل جداً
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  
  const backgroundImageUrl = "https://img.freepik.com/photos-premium/banniere-pour-page-menu-table-cuisine-legumes-epices-ustensiles-fond-sombre-vue-dessus-espace-libre-pour-texte_187166-66331.jpg?semt=ais_hybrid&w=740&q=80";
  
  const texts = ["مرحباً", "أهلاً", "تفضلوا", "استمتعوا"];

  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "linear-gradient(135deg, #ff6b6b, #ee5a24)", size: 210, top: "12%", left: "8%", rotate: -8, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png", delay: 0 },
    { id: 2, name: "أكل", icon: "🍔", color: "linear-gradient(135deg, #4ecdc4, #44bdac)", size: 200, bottom: "12%", left: "10%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png", delay: 0.1 },
    { id: 3, name: "مشروبات", icon: "🥤", color: "linear-gradient(135deg, #45b7d1, #3498db)", size: 205, top: "15%", right: "8%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png", delay: 0.2 },
    { id: 4, name: "ديسار", icon: "🍰", color: "linear-gradient(135deg, #f9ca24, #f39c12)", size: 195, bottom: "15%", right: "10%", rotate: 7, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png", delay: 0.3 }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2800);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 50,
        y: (e.clientY / window.innerHeight - 0.5) * 50
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const handleCardClick = (cardName) => {
    alert(`✨ لقد اخترت: ${cardName} ✨`);
  };

  return (
    <div style={{
      minHeight: "100vh",
      backgroundImage: `url(${backgroundImageUrl})`,
      backgroundSize: "cover",
      backgroundPosition: "center",
      backgroundRepeat: "no-repeat",
      backgroundAttachment: "fixed",
      position: "relative",
      overflow: "hidden",
      fontFamily: "'Cairo', 'Tajawal', sans-serif"
    }}>
      
      {/* تأثير ضبابي خفيف */}
      <div style={{
        position: "absolute",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: "radial-gradient(circle at center, transparent 0%, rgba(0,0,0,0.2) 100%)",
        pointerEvents: "none",
        zIndex: 1
      }}></div>

      {/* جزيئات متحركة */}
      {[...Array(30)].map((_, i) => (
        <div key={i} style={{
          position: "absolute",
          left: `${Math.random() * 100}%`,
          top: `${Math.random() * 100}%`,
          width: `${Math.random() * 4 + 2}px`,
          height: `${Math.random() * 4 + 2}px`,
          background: `rgba(255,255,255,${Math.random() * 0.5})`,
          borderRadius: "50%",
          animation: `float ${Math.random() * 5 + 3}s infinite ease-in-out`,
          pointerEvents: "none",
          zIndex: 2
        }}></div>
      ))}

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0px) translateX(0px); opacity: 0.3; }
          50% { transform: translateY(-20px) translateX(10px); opacity: 1; }
        }
        @keyframes pulse {
          0%, 100% { transform: scale(1); opacity: 0.7; }
          50% { transform: scale(1.05); opacity: 1; }
        }
        @keyframes glow {
          0%, 100% { text-shadow: 0 0 20px rgba(34,197,94,0.5); }
          50% { text-shadow: 0 0 40px rgba(34,197,94,0.8); }
        }
      `}</style>

      {/* الكاردات */}
      {cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card.name)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.7 : -0.6)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.6 : 0.7)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.25s cubic-bezier(0.2, 0.9, 0.4, 1.1)",
            zIndex: 15,
            cursor: "pointer",
            animation: `float ${Math.random() * 2 + 3}s infinite ease-in-out`,
            animationDelay: `${card.delay}s`
          }}
        >
          <div style={{
            background: card.color,
            width: `${card.size}px`,
            padding: "35px 20px",
            borderRadius: "50px",
            textAlign: "center",
            boxShadow: "0 30px 50px rgba(0,0,0,0.4), 0 0 0 2px rgba(255,255,255,0.2) inset",
            backdropFilter: "blur(10px)",
            transition: "all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)",
            position: "relative",
            overflow: "hidden"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.15) rotate(${card.rotate + 12}deg)`;
            e.currentTarget.style.boxShadow = "0 45px 70px rgba(0,0,0,0.5), 0 0 0 3px rgba(34,197,94,0.6) inset";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 30px 50px rgba(0,0,0,0.4), 0 0 0 2px rgba(255,255,255,0.2) inset";
          }}
          >
            <div style={{
              position: "absolute",
              top: "-50%",
              left: "-50%",
              width: "200%",
              height: "200%",
              background: "radial-gradient(circle, rgba(255,255,255,0.2), transparent)",
              transform: "rotate(45deg)",
              pointerEvents: "none"
            }}></div>
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "90px", 
                height: "90px", 
                marginBottom: "15px", 
                filter: "drop-shadow(0 8px 20px rgba(0,0,0,0.3))",
                transition: "transform 0.3s"
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "12px 0 8px", 
              fontSize: "1.9rem", 
              fontWeight: "bold",
              textShadow: "0 2px 5px rgba(0,0,0,0.3)",
              letterSpacing: "1px"
            }}>{card.name}</h3>
            <span style={{ fontSize: "3rem", filter: "drop-shadow(0 2px 5px rgba(0,0,0,0.3))" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* الكلمة المركزية - تصميم رائع */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.2}px, ${mousePosition.y * 0.2}px)`,
        textAlign: "center",
        zIndex: 25,
        transition: "transform 0.2s ease-out",
        pointerEvents: "none"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.45)",
          backdropFilter: "blur(25px)",
          padding: "50px 90px",
          borderRadius: "100px",
          border: "2px solid rgba(34,197,94,0.4)",
          boxShadow: "0 0 80px rgba(34,197,94,0.2), 0 25px 45px rgba(0,0,0,0.3)",
          animation: "pulse 3s infinite"
        }}>
          <h1 style={{
            fontSize: "6rem",
            fontWeight: "900",
            background: "linear-gradient(135deg, #22c55e, #4ade80, #22c55e)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            margin: 0,
            letterSpacing: "8px",
            animation: "glow 2s infinite"
          }}>
            {texts[textIndex]}
          </h1>
          <div style={{
            width: "180px",
            height: "3px",
            background: "linear-gradient(90deg, transparent, #22c55e, #4ade80, #22c55e, transparent)",
            margin: "30px auto 0",
            borderRadius: "10px"
          }}></div>
          <p style={{
            color: "rgba(255,255,255,0.8)",
            marginTop: "20px",
            fontSize: "0.9rem",
            letterSpacing: "2px"
          }}>
            ✨ اكتشف النكهات المميزة ✨
          </p>
        </div>
      </div>

      {/* تصميم سفلي أنيق */}
      <div style={{
        position: "fixed",
        bottom: "30px",
        left: "50%",
        transform: "translateX(-50%)",
        textAlign: "center",
        zIndex: 30,
        pointerEvents: "none"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.6)",
          backdropFilter: "blur(15px)",
          padding: "8px 24px",
          borderRadius: "50px",
